"use strict";(self.webpackChunkrrbtc_wiki_docusaurus=self.webpackChunkrrbtc_wiki_docusaurus||[]).push([[57401],{7002(i){i.exports=JSON.parse('{"tag":{"label":"lightning","permalink":"/tags/lightning","allTagsPath":"/tags","count":28,"items":[{"id":"concepts/ai-and-bitcoin","title":"AI and Bitcoin","description":"Exploration of the intersection between artificial intelligence and Bitcoin, covering decentralized AI, Lightning payments for AI services, and the risks of AI centralization.","permalink":"/concepts/ai-and-bitcoin"},{"id":"entities/alby","title":"Alby","description":"Browser extension for Bitcoin Lightning payments and Nostr signing. Provides a non-custodial wallet with seamless web integration via the WebLN standard.","permalink":"/entities/alby"},{"id":"comparisons/node-operating-systems","title":"Bitcoin Node Operating Systems","description":"Comparison of Umbrel, StartOS, RaspiBlitz, myNode, RoninDojo, and bare-metal setups for running a Bitcoin + Lightning node at home.","permalink":"/comparisons/node-operating-systems"},{"id":"concepts/bitcoin-node-types","title":"Bitcoin Node Types","description":"Comparison of full, pruned, archival, Simplified Payment Verification (SPV), and neutral nodes; explains trade-offs in storage, trust, privacy, and validation guarantees.","permalink":"/concepts/bitcoin-node-types"},{"id":"entities/bluewallet","title":"BlueWallet","description":"Mobile Bitcoin wallet for iOS and Android. Supports both on-chain and Lightning. Originally included a custodial Lightning option; shifting toward non-custodial with Lightning Dev Kit (LDK) integration.","permalink":"/entities/bluewallet"},{"id":"entities/bolt-card","title":"Bolt Card","description":"Lightning-enabled NFC card for tap-to-pay Bitcoin transactions. Originally from CoinCorner; compatible with third-party Bolt Card Hub services.","permalink":"/entities/bolt-card"},{"id":"entities/breez","title":"Breez","description":"Mobile Lightning wallet for iOS and Android. Built on Flutter. Non-custodial, Lightning-native, and includes a built-in marketplace plus point-of-sale (POS) support.","permalink":"/entities/breez"},{"id":"entities/btcpay-server","title":"BTCPayServer","description":"Self-hosted, open-source payment processor for Bitcoin. Accept on-chain and Lightning payments without relying on third-party custodians.","permalink":"/entities/btcpay-server"},{"id":"entities/c-lightning","title":"C-Lightning (Core-Lightning)","description":"Core-Lightning (CLN, often called c-lightning) is a lightweight, modular Lightning Network implementation. It is notable for early support of Bolt 12, which enables static Lightning offers for automated recurring payments.","permalink":"/entities/c-lightning"},{"id":"entities/casdcr","title":"CASCDR","description":"A decentralized AI service platform built on the Bitcoin Lightning Network. CASCDR provides private, pay-as-you-go AI tools for content creators, using Lightning payments to preserve user privacy and enable permissionless access.","permalink":"/entities/casdcr"},{"id":"entities/cashu","title":"Cashu","description":"Cashu is a free and open-source Chaumian ecash system built for Bitcoin. It lets users hold and transfer ecash tokens offline, settling against the Lightning Network when needed. Nobody needs to know who you are, how much you hold, or with whom you transact.","permalink":"/entities/cashu"},{"id":"concepts/chaumian-ecash","title":"Chaumian eCash","description":"Explanation of Chaumian eCash principles, blind signatures, and modern implementations like Cashu and Fedimint for private, custodial or federated ecash on Bitcoin.","permalink":"/concepts/chaumian-ecash"},{"id":"entities/ibexpay","title":"IBEXPay","description":"Merchant payment processor for accepting Bitcoin via Lightning and on-chain. Targets businesses from single-location shops to multi-location chains.","permalink":"/entities/ibexpay"},{"id":"concepts/lightning-network","title":"Lightning Network","description":"Overview of Lightning Network architecture, channel management, routing, Bolt 12 offers, and trade-offs versus on-chain and other Layer 2 solutions.","permalink":"/concepts/lightning-network"},{"id":"entities/lnbits","title":"LNbits","description":"An open-source Lightning accounting system that sits on top of a Lightning node. Provides a web interface, wallet system, and extensions for building Lightning-powered applications.","permalink":"/entities/lnbits"},{"id":"entities/muun","title":"Muun","description":"Self-custodial Bitcoin wallet with a hybrid Lightning/on-chain model. Uses submarine swaps to enable Lightning payments without the user managing channels directly.","permalink":"/entities/muun"},{"id":"entities/mynode","title":"MyNode","description":"MyNode is a plug-and-play Bitcoin node OS similar to Umbrel, bundling Bitcoin Core, LND, Electrum, BTCPay, JoinMarket, Whirlpool, and more.","permalink":"/entities/mynode"},{"id":"entities/nutstash","title":"Nutstash","description":"Web-based Cashu ecash wallet. Enables users to hold and transfer Chaumian ecash tokens backed by Lightning Network bitcoin.","permalink":"/entities/nutstash"},{"id":"entities/opennode","title":"OpenNode","description":"Bitcoin payment processor for businesses. Settles payments via Lightning and on-chain with an API, e-commerce plugins, and hosted payment pages.","permalink":"/entities/opennode"},{"id":"entities/oshi-app","title":"Oshi App","description":"Bitcoin rewards and marketing platform for local businesses. Replaces traditional loyalty stars, punch cards, and points with bitcoin-backed incentives.","permalink":"/entities/oshi-app"},{"id":"entities/phoenix","title":"Phoenix","description":"Self-custodial Lightning wallet by ACINQ. Designed to abstract channel management from the user while keeping keys on-device.","permalink":"/entities/phoenix"},{"id":"entities/plebdevs","title":"PlebDevs","description":"A Bitcoin developer education initiative founded by Austin (@bitcoinplebdev) that teaches plebs to become technical builders on Bitcoin, Lightning, and Nostr. Operates out of PlebLab in Austin, TX.","permalink":"/entities/plebdevs"},{"id":"entities/polar","title":"Polar","description":"A one-click Lightning Network simulator for local development and testing. Runs inside Docker and lets developers spin up private networks with multiple node implementations without touching mainnet.","permalink":"/entities/polar"},{"id":"entities/raspiblitz","title":"RaspiBlitz","description":"RaspiBlitz is a DIY Bitcoin Lightning node project built for education. Unlike commercial plug-and-play nodes, it emphasizes learning the underlying tools.","permalink":"/entities/raspiblitz"},{"id":"entities/robosats","title":"RoboSats","description":"RoboSats is a peer-to-peer exchange for buying and selling bitcoin using Lightning Network payments. It operates entirely over Tor and uses temporary robot identities, meaning users do not accumulate persistent trade history or reputation.","permalink":"/entities/robosats"},{"id":"entities/strike","title":"Strike","description":"Consumer-friendly Bitcoin and Lightning payment application. Allows users to buy, sell, and send bitcoin with a focus on simplicity and low fees.","permalink":"/entities/strike"},{"id":"entities/umbrel","title":"Umbrel","description":"Umbrel is a plug-and-play Bitcoin node OS designed for Raspberry Pi and x86 mini PCs. It bundles Bitcoin Core, Lightning implementations, and a growing app store.","permalink":"/entities/umbrel"},{"id":"entities/zeus","title":"Zeus","description":"Mobile Lightning wallet and node management app. Connects to your own Lightning node (LND, Core Lightning, or Eclair) remotely, giving you full control without running a node on your phone.","permalink":"/entities/zeus"}],"unlisted":false}}')}}]);